const watchedRoot = '/home/node/.n8n-files/crispybrain/inbox';
const eventName = typeof $json.event === 'string' ? $json.event : '';
const containerPath = typeof $json.path === 'string' ? $json.path : '';
const slugPattern = /^[a-z0-9]+(?:[-_][a-z0-9]+)*$/;
if (eventName !== 'add') {
  return [];
}
if (!containerPath.startsWith(watchedRoot + '/')) {
  return [];
}
const relativePath = containerPath.slice(watchedRoot.length + 1);
const segments = relativePath.split('/').filter(Boolean);
if (segments.length < 2) {
  return [];
}
const projectSlug = segments[0];
const filename = segments[segments.length - 1];
if (!slugPattern.test(projectSlug)) {
  return [];
}
if (!/\.txt$/i.test(filename)) {
  return [];
}
const runId = 'auto-ingest-watch-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const trace = {
  run_id: runId,
  correlation_id: runId,
  workflow_name: 'auto-ingest-watch',
  project_slug: projectSlug,
  source_type: 'file_watch',
  filename,
  filepath: containerPath,
  stage: 'detected',
  status: 'accepted',
  error_code: null,
  error_message: null,
  timestamp: new Date().toISOString(),
  workflow_chain: ['auto-ingest-watch'],
  stage_history: [
    {
      stage: 'detected',
      status: 'accepted',
      timestamp: new Date().toISOString(),
      error_code: null,
      error_message: null
    }
  ]
};
return [{
  json: {
    event: eventName,
    container_path: containerPath,
    relative_path: relativePath,
    filename,
    project_slug: projectSlug,
    source_type: 'file_watch',
    trace,
  },
}];

const base = $('Normalize Watch Event').first().json;
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const content = buffer.toString('utf8').replace(/\r\n/g, '\n');
const withStage = (trace, stage, status, extra = {}) => {
  const timestamp = new Date().toISOString();
  const errorCode = Object.prototype.hasOwnProperty.call(extra, 'error_code') ? extra.error_code : (trace.error_code ?? null);
  const errorMessage = Object.prototype.hasOwnProperty.call(extra, 'error_message') ? extra.error_message : (trace.error_message ?? null);
  return {
    ...trace,
    ...extra,
    stage,
    status,
    error_code: errorCode,
    error_message: errorMessage,
    timestamp,
    stage_history: [
      ...(Array.isArray(trace.stage_history) ? trace.stage_history : []),
      { stage, status, timestamp, error_code: errorCode, error_message: errorMessage },
    ],
  };
};
return [{
  json: {
    filepath: base.container_path,
    filename: base.filename,
    content,
    project_slug: base.project_slug,
    source_type: base.source_type,
    trace: withStage(base.trace, 'payload_ready', 'accepted'),
  },
}];

const request = $('Build Ingest Payload').first().json;
const statusCode = $json.statusCode ?? 0;
const body = $json.body ?? {};
const ok = statusCode >= 200 && statusCode < 300 && body.ok === true;
return [{
  json: {
    ok,
    statusCode,
    watched_path: request.filepath,
    filename: request.filename,
    project_slug: request.project_slug,
    ingest_response_ok: body.ok ?? null,
    ingest_workflow: body.trace?.workflow_name ?? null,
    ingest_stage: body.trace?.stage ?? null,
    error: ok ? null : (body.error ?? { code: 'UPSTREAM_HTTP_ERROR', message: 'Canonical ingest webhook failed' }),
  },
}];
